def _plain_value(value: Any) -> Any:
    """Strip dataclasses/mappings to plain JSON-friendly Python values.

    Used by `ListResult.to_dict` / `AsyncListResult.to_dict` so callers get
    a dict back without dragging private dataclass identity through. Any
    other dataclass that needs a dict view should expose its own
    `to_json()` (which returns a `JsonObject`) — there is no inherited
    `to_dict` mixin because that pattern collided with the dataclass
    `to_json() -> JsonObject` convention.
    """
    if is_dataclass(value) and not isinstance(value, type):
        return {
            key: _plain_value(item)
            for key, item in asdict(value).items()
            if item is not None
        }
    if isinstance(value, Mapping):
        return {
            str(key): _plain_value(item)
            for key, item in value.items()
            if item is not None
        }
    if isinstance(value, (list, tuple)):
        return [_plain_value(item) for item in value]
    return value


