def _drop_empty(
    value: Mapping[str, Any], *, preserve_empty_strings: bool = False
) -> JsonObject:
    stripped: JsonObject = {}
    for key, item in value.items():
        if item is None or item == [] or item == {}:
            continue
        if item == "" and not preserve_empty_strings:
            continue
        if isinstance(item, Mapping):
            nested = _drop_empty(
                item,
                preserve_empty_strings=_preserves_empty_string_map(key, item),
            )
            if nested:
                stripped[key] = nested
        else:
            stripped[key] = item
    return stripped


strip_empty = _drop_empty


def _preserves_empty_string_map(key: str, value: Mapping[str, Any]) -> bool:
    if key in _STRING_MAP_FIELDS:
        return True
    if key != "env":
        return False
    if "type" in value or "name" in value:
        return False
    return all(isinstance(item, str) for item in value.values())


def _enum(value: str | None, prefix: str) -> str | None:
    if value is None:
        return None
    if value.startswith(prefix):
        return value
    return f"{prefix}{value.upper()}"


def _as_mapping(value: object) -> Mapping[str, Any]:
    if isinstance(value, Mapping):
        return value
    raise TypeError(f"Expected a mapping, got {type(value).__name__}")


def _string(value: Mapping[str, Any], key: str, default: str = "") -> str:
    item = value.get(key, default)
    return str(item) if item is not None else default


def _string_any(value: Mapping[str, Any], *keys: str, default: str = "") -> str:
    for key in keys:
        item = value.get(key)
        if item is not None:
            return str(item)
    return default


def _int(value: Mapping[str, Any], key: str, default: int = 0) -> int:
    item = value.get(key)
    if item is None:
        return default
    try:
        return int(item)
    except (TypeError, ValueError):
        return default


def _bool(value: Mapping[str, Any], key: str, default: bool = False) -> bool:
    item = value.get(key)
    return default if item is None else bool(item)


def _normal_runtime(value: str) -> str:
    return value.removeprefix("RUNTIME_").lower()


def _normal_run_status(value: str) -> RunStatus:
    normalized = value.removeprefix("RUN_LIFECYCLE_STATUS_").lower()
    if normalized == "unspecified":
        return "error"
    if normalized == "creating":
        return "running"
    if normalized in {"running", "finished", "error", "cancelled", "expired"}:
        return cast(RunStatus, normalized)
    return "error"


normalize_run_status = _normal_run_status


def _normal_agent_status(value: str) -> str | None:
    normalized = value.removeprefix("AGENT_INFO_STATUS_").lower()
    return normalized if normalized in {"running", "finished", "error"} else None


@dataclass(frozen=True)
class ListResult(Generic[_T]):
    items: list[_T]
    next_cursor: str = ""
    _get_next_page: Callable[[str], "ListResult[_T]"] | None = field(
        default=None,
        repr=False,
        compare=False,
    )

    def __iter__(self) -> Iterator[_T]:
        return iter(self.items)

    def __len__(self) -> int:
        return len(self.items)

    def __getitem__(self, index: int) -> _T:
        return self.items[index]

    def to_dict(self) -> dict[str, Any]:
        return {"items": _plain_value(self.items), "next_cursor": self.next_cursor}

    def has_next_page(self) -> bool:
        return bool(self.next_cursor)

    def next_page_info(self) -> dict[str, str]:
        return {"cursor": self.next_cursor} if self.next_cursor else {}

    def get_next_page(self) -> "ListResult[_T]":
        if not self.next_cursor:
            return ListResult(items=[])
        if self._get_next_page is None:
            raise ConfigurationError(
                "This ListResult was not created by a pageable SDK method.",
                code="pagination_unavailable",
            )
        return self._get_next_page(self.next_cursor)

    def auto_paging_iter(self) -> Iterator[_T]:
        page: ListResult[_T] = self
        while True:
            yield from page.items
            if not page.next_cursor:
                return
            page = page.get_next_page()


@dataclass(frozen=True)
class AsyncListResult(Generic[_T]):
    items: list[_T]
    next_cursor: str = ""
    _get_next_page: Callable[[str], Awaitable["AsyncListResult[_T]"]] | None = field(
        default=None,
        repr=False,
        compare=False,
    )

    def __iter__(self) -> Iterator[_T]:
        return iter(self.items)

    def __len__(self) -> int:
        return len(self.items)

    def __getitem__(self, index: int) -> _T:
        return self.items[index]

    def to_dict(self) -> dict[str, Any]:
        return {"items": _plain_value(self.items), "next_cursor": self.next_cursor}

    def __aiter__(self) -> AsyncIterator[_T]:
        # PEP 492 specifies `__aiter__` as a regular method that returns an
        # async iterator; only the helper below is `async def` (and therefore
        # an async generator). Mirrors `ListResult.__iter__`: yields items
        # from the current page only. Use `page.auto_paging_iter()` to walk
        # every page across the full result set.
        return self._aiter_current_page()

    async def _aiter_current_page(self) -> AsyncIterator[_T]:
        for item in self.items:
            yield item

    def has_next_page(self) -> bool:
        return bool(self.next_cursor)

    def next_page_info(self) -> dict[str, str]:
        return {"cursor": self.next_cursor} if self.next_cursor else {}

    async def get_next_page(self) -> "AsyncListResult[_T]":
        if not self.next_cursor:
            return AsyncListResult(items=[])
        if self._get_next_page is None:
            raise ConfigurationError(
                "This AsyncListResult was not created by a pageable SDK method.",
                code="pagination_unavailable",
            )
        return await self._get_next_page(self.next_cursor)

    async def auto_paging_iter(self) -> AsyncIterator[_T]:
        page: AsyncListResult[_T] = self
        while True:
            for item in page.items:
                yield item
            if not page.next_cursor:
                return
            page = await page.get_next_page()


@dataclass(frozen=True)
class ModelParameterValue:
    id: str
    value: str

    @classmethod
    def from_json(cls, value: Mapping[str, Any]) -> "ModelParameterValue":
        return cls(id=_string(value, "id"), value=_string(value, "value"))

    def to_json(self) -> JsonObject:
        return {"id": self.id, "value": self.value}


@dataclass(frozen=True)
class ModelSelection:
    id: str
    params: Sequence[ModelParameterValue] = ()

    @classmethod
    def from_value(
        cls, value: str | Mapping[str, Any] | "ModelSelection"
    ) -> "ModelSelection":
        if isinstance(value, cls):
            return value
        if isinstance(value, str):
            return cls(id=value)
        mapping = _as_mapping(value)
        return cls(
            id=_string(mapping, "id"),
            params=tuple(
                param
                if isinstance(param, ModelParameterValue)
                else ModelParameterValue.from_json(_as_mapping(param))
                for param in mapping.get("params", [])
            ),
        )

    @classmethod
    def from_json(cls, value: Mapping[str, Any]) -> "ModelSelection":
        return cls.from_value(value)

    def to_json(self) -> JsonObject:
        return _drop_empty(
            {"id": self.id, "params": [param.to_json() for param in self.params]}
        )


