def _custom_tool_definition_to_wire(tool: CustomTool | Mapping[str, Any]) -> JsonObject:
    if isinstance(tool, CustomTool):
        wire = _drop_empty(
            {
                "description": tool.description,
                "inputSchema": dict(tool.input_schema) if tool.input_schema else None,
            }
        )
        return wire if wire else {}
    payload = dict(tool)
    if "input_schema" in payload and "inputSchema" not in payload:
        payload["inputSchema"] = payload.pop("input_schema")
    payload.pop("execute", None)
    wire = _drop_empty(payload)
    return wire if wire else {}


def _custom_tools_to_wire(
    custom_tools: Mapping[str, CustomTool | Mapping[str, Any]] | None,
) -> dict[str, JsonObject]:
    if not custom_tools:
        return {}
    return {
        name: _custom_tool_definition_to_wire(tool)
        for name, tool in custom_tools.items()
    }


def _normalize_custom_tools_wire(
    custom_tools: Mapping[str, Any],
) -> dict[str, JsonObject]:
    normalized: dict[str, JsonObject] = {}
    for name, tool in custom_tools.items():
        if isinstance(tool, CustomTool):
            normalized[name] = _custom_tool_definition_to_wire(tool)
        elif isinstance(tool, Mapping):
            normalized[name] = _custom_tool_definition_to_wire(tool)
        else:
            raise ConfigurationError(
                f'custom_tools["{name}"] must be a CustomTool or mapping'
            )
    return normalized


@dataclass(frozen=True)
class LocalAgentOptions:
    cwd: Sequence[str | os.PathLike[str]] | str | os.PathLike[str] | None = None
    setting_sources: Sequence[SettingSource | str] | None = None
    sandbox_options: SandboxOptions | Mapping[str, Any] | None = None
    store: LocalAgentStoreConfig | Mapping[str, Any] | None = None
    auto_review: bool | None = None
    custom_tools: Mapping[str, CustomTool | Mapping[str, Any]] | None = None

    def to_json(self) -> JsonObject:
        if self.cwd is None:
            cwd: list[str] = []
        elif isinstance(self.cwd, (str, os.PathLike)):
            cwd = [os.fspath(self.cwd)]
        else:
            cwd = [os.fspath(item) for item in self.cwd]
        sandbox_options = self.sandbox_options
        if isinstance(sandbox_options, SandboxOptions):
            sandbox_json = sandbox_options.to_json()
        else:
            sandbox_json = dict(sandbox_options or {})
        store = self.store
        if isinstance(store, LocalAgentStoreConfig):
            store_json = store.to_json()
        else:
            store_json = _normalize_local_store(dict(store or {}))
        payload = _drop_empty(
            {
                "cwd": cwd,
                "settingSources": [
                    _enum(str(source), "SETTING_SOURCE_")
                    for source in (self.setting_sources or ())
                ],
                "sandboxOptions": sandbox_json,
                "store": store_json,
                "autoReview": self.auto_review,
            }
        )
        if self.custom_tools:
            payload["customTools"] = _custom_tools_to_wire(self.custom_tools)
        return payload


