@dataclass(frozen=True)
class McpAuth:
    """OAuth2 client credentials for HTTP / SSE MCP servers.

    Snake-case Python fields map to camelCase wire fields on serialization.
    Raw dicts with the SCREAMING_SNAKE_CASE keys (`CLIENT_ID`, `CLIENT_SECRET`,
    `SCOPES`) are still normalized for back-compat in `_normalize_mcp_auth`,
    but new code should use this dataclass.
    """

    client_id: str
    client_secret: str | None = None
    scopes: Sequence[str] = ()

    def to_json(self) -> JsonObject:
        return _drop_empty(
            {
                "clientId": self.client_id,
                "clientSecret": self.client_secret,
                "scopes": list(self.scopes),
            }
        )


