@dataclass(frozen=True)
class SDKImage:
    url: str | None = None
    data: str | None = None
    mime_type: str | None = None
    dimension: SDKImageDimension | Mapping[str, Any] | None = None

    @classmethod
    def from_url(
        cls, url: str, dimension: SDKImageDimension | Mapping[str, Any] | None = None
    ) -> "SDKImage":
        return cls(url=url, dimension=dimension)

    @classmethod
    def url_image(
        cls, url: str, dimension: SDKImageDimension | Mapping[str, Any] | None = None
    ) -> "SDKImage":
        return cls.from_url(url, dimension=dimension)

    @classmethod
    def from_data(
        cls,
        data: bytes | str,
        mime_type: str,
        dimension: SDKImageDimension | Mapping[str, Any] | None = None,
    ) -> "SDKImage":
        encoded = (
            base64.b64encode(data).decode("ascii") if isinstance(data, bytes) else data
        )
        return cls(data=encoded, mime_type=mime_type, dimension=dimension)

    @classmethod
    def from_file(
        cls,
        path: str | os.PathLike[str],
        *,
        mime_type: str | None = None,
        dimension: SDKImageDimension | Mapping[str, Any] | None = None,
    ) -> "SDKImage":
        file_path = os.fspath(path)
        with open(file_path, "rb") as image_file:
            data = image_file.read()
        detected_mime_type = mime_type or mimetypes.guess_type(file_path)[0]
        return cls.from_data(
            data,
            detected_mime_type or "application/octet-stream",
            dimension=dimension,
        )

    @classmethod
    def data_image(
        cls,
        data: str,
        mime_type: str,
        dimension: SDKImageDimension | Mapping[str, Any] | None = None,
    ) -> "SDKImage":
        return cls.from_data(data, mime_type, dimension=dimension)

    def to_json(self) -> JsonObject:
        dimension = (
            self.dimension.to_json()
            if isinstance(self.dimension, SDKImageDimension)
            else self.dimension
        )
        output: JsonObject = {}
        if self.url:
            output["url"] = {"url": self.url}
        elif self.data:
            output["data"] = {"data": self.data, "mimeType": self.mime_type}
        if dimension is not None:
            output["dimension"] = dict(dimension or {})
        return _drop_empty(output)


@dataclass(frozen=True)
class UserMessage:
    text: str
    images: Sequence[SDKImage | Mapping[str, Any]] | None = None

    @classmethod
    def from_value(
        cls, value: str | Mapping[str, Any] | "UserMessage"
    ) -> "UserMessage":
        if isinstance(value, cls):
            return value
        if isinstance(value, str):
            return cls(text=value)
        mapping = _as_mapping(value)
        return cls(
            text=_string(mapping, "text"),
            images=tuple(mapping.get("images", [])) or None,
        )

    def to_json(self) -> JsonObject:
        return _drop_empty(
            {
                "text": self.text,
                "images": [
                    _image_to_proto_wire(image) for image in (self.images or ())
                ],
            }
        )


SDKUserMessage = UserMessage


def _image_to_proto_wire(image: SDKImage | Mapping[str, Any]) -> JsonObject:
    if isinstance(image, SDKImage):
        return image.to_json()
    mapping: JsonObject = dict(image)
    dimension = mapping.pop("dimension", None)
    output: JsonObject = {}
    if "url" in mapping and mapping["url"]:
        url_field = mapping["url"]
        output["url"] = (
            url_field if isinstance(url_field, Mapping) else {"url": str(url_field)}
        )
    elif "data" in mapping and mapping["data"]:
        data_field = mapping["data"]
        if isinstance(data_field, Mapping):
            output["data"] = dict(data_field)
        else:
            output["data"] = {
                "data": str(data_field),
                "mimeType": str(mapping.get("mimeType", "")),
            }
    if dimension is not None:
        output["dimension"] = (
            dimension.to_json()
            if isinstance(dimension, SDKImageDimension)
            else dict(dimension)
            if isinstance(dimension, Mapping)
            else {}
        )
    return _drop_empty(output)


