SDKMessage = (
    SDKSystemMessage
    | SDKUserMessageEvent
    | SDKAssistantMessage
    | SDKThinkingMessage
    | SDKToolUseMessage
    | SDKStatusMessage
    | SDKTaskMessage
    | SDKRequestMessage
    | SDKUsageMessage
    | Mapping[str, Any]
)


def sdk_message_from_json(value: Mapping[str, Any]) -> SDKMessage:
    payload = _sdk_message_payload(value)
    message_type = _string(payload, "type") or _string(value, "type")
    agent_id = _string_any(payload, "agent_id", "agentId")
    run_id = _string_any(payload, "run_id", "runId")
    if message_type == "system":
        return SDKSystemMessage(
            type="system",
            agent_id=agent_id,
            run_id=run_id,
            subtype=_string(payload, "subtype"),
            model=ModelSelection.from_json(_as_mapping(payload["model"]))
            if payload.get("model")
            else None,
            tools=tuple(str(tool) for tool in payload.get("tools", [])),
        )
    if message_type == "user":
        return SDKUserMessageEvent(
            type="user",
            agent_id=agent_id,
            run_id=run_id,
            message=_user_message_content_from_json(payload.get("message")),
        )
    if message_type == "assistant":
        return SDKAssistantMessage(
            type="assistant",
            agent_id=agent_id,
            run_id=run_id,
            message=_assistant_message_content_from_json(payload.get("message")),
        )
    if message_type == "thinking":
        duration_value = payload.get("thinkingDurationMs")
        if duration_value is None:
            duration_value = payload.get("thinking_duration_ms")
        return SDKThinkingMessage(
            type="thinking",
            agent_id=agent_id,
            run_id=run_id,
            text=_string(payload, "text"),
            thinking_duration_ms=(
                _int({"thinkingDurationMs": duration_value}, "thinkingDurationMs")
                if duration_value is not None
                else None
            ),
        )
    if message_type == "tool_call":
        return SDKToolUseMessage(
            type="tool_call",
            agent_id=agent_id,
            run_id=run_id,
            call_id=_string_any(payload, "call_id", "callId"),
            name=_string(payload, "name"),
            status=_string(payload, "status"),
            args=payload.get("args"),
            result=payload.get("result"),
            truncated=dict(payload["truncated"])
            if isinstance(payload.get("truncated"), Mapping)
            else None,
        )
    if message_type == "status":
        return SDKStatusMessage(
            type="status",
            agent_id=agent_id,
            run_id=run_id,
            status=_string(payload, "status"),
            message=_string(payload, "message"),
        )
    if message_type == "task":
        return SDKTaskMessage(
            type="task",
            agent_id=agent_id,
            run_id=run_id,
            status=_string(payload, "status"),
            text=_string(payload, "text"),
        )
    if message_type == "request":
        return SDKRequestMessage(
            type="request",
            agent_id=agent_id,
            run_id=run_id,
            request_id=_string_any(payload, "request_id", "requestId"),
        )
    if message_type == "usage":
        usage_payload = payload.get("usage")
        if not isinstance(usage_payload, Mapping) or not _has_reported_token_usage(
            usage_payload
        ):
            return dict(payload)
        return SDKUsageMessage(
            type="usage",
            agent_id=agent_id,
            run_id=run_id,
            usage=TokenUsage.from_json(usage_payload),
        )
    return dict(payload)


def _sdk_message_payload(value: Mapping[str, Any]) -> Mapping[str, Any]:
    message = value.get("message")
    if isinstance(message, Mapping) and "type" in message:
        return message
    return value


def _user_message_content_from_json(value: Any) -> SDKUserMessageContent:
    mapping = _as_mapping(value or {})
    return SDKUserMessageContent(
        role="user",
        content=tuple(
            TextBlock.from_json(_as_mapping(block))
            if isinstance(block, Mapping) and block.get("type") == "text"
            else dict(block)
            for block in mapping.get("content", [])
            if isinstance(block, Mapping)
        ),
    )


def _assistant_message_content_from_json(value: Any) -> SDKAssistantMessageContent:
    mapping = _as_mapping(value or {})
    return SDKAssistantMessageContent(
        role="assistant",
        content=tuple(
            _content_block_from_json(_as_mapping(block))
            for block in mapping.get("content", [])
            if isinstance(block, Mapping)
        ),
    )


