def options_to_json(
    options: AgentOptions | Mapping[str, Any] | None,
    *,
    model: str | ModelSelection | Mapping[str, Any] | None = None,
    api_key: str | None = None,
    name: str | None = None,
    local: LocalAgentOptions | Mapping[str, Any] | None = None,
    cloud: CloudAgentOptions | Mapping[str, Any] | None = None,
) -> JsonObject:
    if options is None:
        return AgentOptions(
            model=model, api_key=api_key, name=name, local=local, cloud=cloud
        ).to_json()
    if isinstance(options, AgentOptions):
        base = options.to_json()
    else:
        # `_normalize_agent_options_mapping` already converts snake_case
        # keys, runs `_normalize_local_options`, and calls
        # `_normalize_cloud_options` on a mapping `cloud` value, so we only
        # have model/MCP-server normalization to apply here.
        base = _normalize_agent_options_mapping(options)
        model_value = base.get("model")
        if model_value:
            base["model"] = ModelSelection.from_value(model_value).to_json()
        if isinstance(base.get("mcpServers"), Mapping):
            base["mcpServers"] = _normalize_mcp_servers(base["mcpServers"])
    overrides = AgentOptions(
        model=model, api_key=api_key, name=name, local=local, cloud=cloud
    ).to_json()
    # Both `base` and `overrides` were already passed through to_json /
    # _drop_empty individually. Merge them once and return without a second
    # _drop_empty pass: the trailing pass would recursively strip any value
    # the inner converters intentionally kept (e.g. an explicit empty list
    # or a caller-passed empty mapping) and produce results asymmetric with
    # the `options is None` early-return path above.
    return _deep_merge(base, overrides)


_ATOMIC_OPTION_KEYS = {"model"}


def _deep_merge(base: Mapping[str, Any], overrides: Mapping[str, Any]) -> JsonObject:
    merged: JsonObject = dict(base)
    for key, value in overrides.items():
        merged_val = merged.get(key)
        if (
            key not in _ATOMIC_OPTION_KEYS
            and isinstance(value, Mapping)
            and isinstance(merged_val, Mapping)
        ):
            merged[key] = _deep_merge(merged_val, value)
        else:
            # Atomic keys (e.g. 'model') replace wholesale on override, so a
            # caller passing model='gpt-4' does not silently inherit the prior
            # model's params dict from the base ModelSelection.
            merged[key] = value
    return merged


def agent_options_idempotency_key(
    options: AgentOptions | Mapping[str, Any] | None,
) -> str | None:
    if isinstance(options, AgentOptions):
        return options.idempotency_key
    if isinstance(options, Mapping):
        item = options.get("idempotencyKey") or options.get("idempotency_key")
        return str(item) if item else None
    return None


def send_options_to_json(options: SendOptions | Mapping[str, Any] | None) -> JsonObject:
    if options is None:
        return {}
    if isinstance(options, SendOptions):
        return options.to_json()
    normalized = _normalize_send_options_mapping(options)
    model_value = normalized.get("model")
    if model_value:
        normalized["model"] = ModelSelection.from_value(model_value).to_json()
    if isinstance(normalized.get("mcpServers"), Mapping):
        normalized["mcpServers"] = _normalize_mcp_servers(normalized["mcpServers"])
    return normalized


def send_options_idempotency_key(
    options: SendOptions | Mapping[str, Any] | None,
) -> str | None:
    if isinstance(options, SendOptions):
        return options.idempotency_key
    if isinstance(options, Mapping):
        item = options.get("idempotencyKey") or options.get("idempotency_key")
        return str(item) if item else None
    return None


def chunks_to_bytes(chunks: Iterable[Mapping[str, Any]]) -> bytes:
    parts = []
    for chunk in chunks:
        data = chunk.get("data", "")
        if isinstance(data, str):
            parts.append(base64.b64decode(data))
        else:
            parts.append(bytes(data))
    return b"".join(parts)
